import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ServiceSetting } from '../../core/models';

@Component({
  selector: 'app-admin-settings',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './admin-settings.component.html',
  styleUrls: ['./admin-settings.component.css'],
})
export class AdminSettingsComponent {
  readonly saved = signal<string | null>(null);

  // Provisioned services (mockup — service_agent wires GET/PATCH /api/admin/settings).
  readonly settings = signal<ServiceSetting[]>([
    {
      key: 'postgresql', service: 'postgresql', label: 'PostgreSQL Database',
      configured: true, maskedValue: '••••••••••',
      fields: [
        { key: 'DATABASE_URL', label: 'Connection URL', placeholder: 'postgres://user:pass@host:5432/db' },
      ],
    },
    {
      key: 'minio', service: 'minio', label: 'MinIO Object Storage',
      configured: false, maskedValue: '',
      fields: [
        { key: 'MINIO_ENDPOINT', label: 'Endpoint', placeholder: 'https://minio.example.com' },
        { key: 'MINIO_ACCESS_KEY', label: 'Access Key', placeholder: 'access key' },
        { key: 'MINIO_SECRET_KEY', label: 'Secret Key', placeholder: 'secret key' },
      ],
    },
  ]);

  readonly values: Record<string, string> = {};

  save(setting: ServiceSetting): void {
    this.settings.update((list) =>
      list.map((s) => (s.key === setting.key ? { ...s, configured: true, maskedValue: '••••••••••' } : s)),
    );
    this.saved.set(setting.label);
    setTimeout(() => this.saved.set(null), 2500);
  }
}
